-- Replace HSK4 examples with contextual, unique examples.
-- Template HSK4 is refreshed. User cards are updated only when the old generic
-- placeholder is still present or the example is blank.
with hsk4_context_examples (
  chinese,
  example_cn,
  example_pinyin,
  example_vi
) as (
  values
    ('爱情', '他们的爱情故事让大家都感动。', 'Tāmen de àiqíng gùshì ràng dàjiā dōu gǎndòng.', 'Câu chuyện tình yêu của họ làm mọi người đều xúc động.'),
    ('按照', '请按照说明书操作机器。', 'Qǐng ànzhào shuōmíngshū cāozuò jīqì.', 'Vui lòng vận hành máy theo hướng dẫn sử dụng.'),
    ('按时', '我们必须按时完成这项任务。', 'Wǒmen bìxū ànshí wánchéng zhè xiàng rènwu.', 'Chúng ta phải hoàn thành nhiệm vụ này đúng hạn.'),
    ('安排', '老师安排了明天的考试时间。', 'Lǎoshī ānpái le míngtiān de kǎoshì shíjiān.', 'Giáo viên đã sắp xếp thời gian thi vào ngày mai.'),
    ('安全', '在工厂工作时，请注意安全。', 'Zài gōngchǎng gōngzuò shí, qǐng zhùyì ānquán.', 'Khi làm việc trong nhà máy, xin hãy chú ý an toàn.'),
    ('百分之', '这道题有百分之八十的人答对了。', 'Zhè dào tí yǒu bǎifēnzhī bāshí de rén dá duì le.', 'Có 80 phần trăm người trả lời đúng câu hỏi này.'),
    ('饼干', '我喜欢和茶一起吃饼干。', 'Wǒ xǐhuān hé chá yīqǐ chī bǐnggān.', 'Tôi thích ăn bánh quy cùng với trà.'),
    ('部分', '这部分材料很重要，要仔细阅读。', 'Zhè bùfèn cáiliào hěn zhòngyào, yào zǐxì yuèdú.', 'Phần tài liệu này rất quan trọng, cần đọc kỹ.'),
    ('遍', '请把这篇文章读一遍。', 'Qǐng bǎ zhè piān wénzhāng dú yí biàn.', 'Xin hãy đọc bài văn này một lượt.'),
    ('表示', '他用微笑表示感谢。', 'Tā yòng wēixiào biǎoshì gǎnxiè.', 'Anh ấy dùng nụ cười để biểu thị lòng biết ơn.'),
    ('表演', '我们班准备下个月进行一次精彩的表演。', 'Wǒmen bān zhǔnbèi xià gè yuè jìnxíng yí cì jīngcǎi de biǎoyǎn.', 'Lớp chúng tôi chuẩn bị có một buổi biểu diễn tuyệt vời vào tháng tới.'),
    ('表格', '请填写这张表格以便我们核对信息。', 'Qǐng tiánxiě zhè zhāng biǎogé yǐbiàn wǒmen héduì xìnxī.', 'Vui lòng điền vào bảng biểu này để chúng tôi kiểm tra thông tin.'),
    ('表扬', '老师表扬了他在课堂上的积极表现。', 'Lǎoshī biǎoyáng le tā zài kètáng shàng de jījí biǎoxiàn.', 'Giáo viên đã tuyên dương sự tích cực của cậu ấy trong lớp học.'),
    ('笨', '别说自己笨，多练习就会进步。', 'Bié shuō zìjǐ bèn, duō liànxí jiù huì jìnbù.', 'Đừng nói mình ngốc, luyện tập nhiều sẽ tiến bộ thôi.'),
    ('毕业', '他今年夏天从大学毕业了。', 'Tā jīnnián xiàtiān cóng dàxué bìyè le.', 'Anh ấy tốt nghiệp đại học vào mùa hè năm nay.'),
    ('比如', '我们学习很多实用的知识，比如如何写商业计划。', 'Wǒmen xuéxí hěn duō shíyòng de zhīshì, bǐrú rúhé xiě shāngyè jìhuà.', 'Chúng tôi học nhiều kiến thức thực tế, ví dụ như cách viết kế hoạch kinh doanh.'),
    ('棒', '孩子用棒子在地上画画。', 'Háizi yòng bàngzi zài dìshàng huà huà.', 'Đứa trẻ dùng cây gậy để vẽ trên đất.'),
    ('标准', '这款产品符合国际质量标准。', 'Zhè kuǎn chǎnpǐn fúhé guójì zhìliàng biāozhǔn.', 'Sản phẩm này đáp ứng tiêu chuẩn chất lượng quốc tế.'),
    ('本来', '我本来打算早点来，可是遇到了交通堵塞。', 'Wǒ běnlái dǎsuàn zǎodiǎn lái, kěshì yùdào le jiāotōng dǔsè.', 'Tôi vốn định đến sớm, nhưng lại gặp phải tắc đường.'),
    ('抱歉', '抱歉，我忘了带你的书。', 'Bàoqiàn, wǒ wàng le dài nǐ de shū.', 'Xin lỗi, tôi đã quên mang cuốn sách của bạn.'),
    ('抱', '她生病了，我去医院抱了她。', 'Tā shēngbìng le, wǒ qù yīyuàn bào le tā.', 'Cô ấy bị ốm, tôi đã đến bệnh viện ôm cô ấy.'),
    ('报名', '我准备报名下个月的汉语考试。', 'Wǒ zhǔnbèi bàomíng xià gè yuè de hànyǔ kǎoshì.', 'Tôi chuẩn bị đăng ký kỳ thi tiếng Trung vào tháng tới.'),
    ('并且', '他不仅会说英语，并且会说法语。', 'Tā bù jǐn huì shuō yīngyǔ, bìngqiě huì shuō fǎyǔ.', 'Anh ấy không chỉ biết nói tiếng Anh mà còn biết nói tiếng Pháp.'),
    ('博士', '她去年完成了博士学位的论文。', 'Tā qùnián wánchéng le bóshì xuéwèi de lùnwén.', 'Cô ấy đã hoàn thành luận án tiến sĩ vào năm ngoái.'),
    ('包子', '早餐我买了几个新鲜的包子。', 'Zǎocān wǒ mǎi le jǐ gè xīnxiān de bāozi.', 'Sáng nay tôi đã mua vài chiếc bánh bao tươi.'),
    ('倍', '今年的销售额比去年增加了两倍。', 'Jīnnián de xiāoshòu''é bǐ qùnián zēngjiā le liǎng bèi.', 'Doanh số năm nay tăng gấp đôi so với năm ngoái.'),
    ('保证', '公司保证产品质量不会有问题。', 'Gōngsī bǎozhèng chǎnpǐn zhìliàng bú huì yǒu wèntí.', 'Công ty đảm bảo chất lượng sản phẩm sẽ không có vấn đề.'),
    ('保护', '我们应该保护环境，减少污染。', 'Wǒmen yīnggāi bǎohù huánjìng, jiǎnshǎo wūrǎn.', 'Chúng ta nên bảo vệ môi trường, giảm thiểu ô nhiễm.'),
    ('不过', '我想去旅行，不过工作太忙没时间。', 'Wǒ xiǎng qù lǚxíng, bùguò gōngzuò tài máng méi shíjiān.', 'Tôi muốn đi du lịch, nhưng công việc quá bận nên không có thời gian.'),
    ('不管', '不管天气怎么样，我们明天都去爬山。', 'Bùguǎn tiānqì zěnmeyàng, wǒmen míngtiān dōu qù páshān.', 'Bất kể thời tiết thế nào, chúng ta ngày mai đều đi leo núi.'),
    ('不得不', '今天下雨了，所以我不得不取消旅行计划。', 'Jīntiān xiàyǔ le, suǒyǐ wǒ bùdébù qǔxiāo lǚxíng jìhuà.', 'Hôm nay trời mưa, nên tôi đành phải hủy kế hoạch du lịch.'),
    ('不仅', '这家餐厅不仅价格合理，而且菜很好吃。', 'Zhè jiā cāntīng bùjǐn jiàgé hélǐ, érqiě cài hěn hǎochī.', 'Nhà hàng này không những giá cả hợp lý, mà món ăn còn rất ngon.'),
    ('擦', '请用布擦一下桌子，保持清洁。', 'Qǐng yòng bù cā yíxià zhuōzi, bǎochí qīngjié.', 'Làm ơn dùng khăn lau cái bàn nhé, giữ cho sạch sẽ.'),
    ('餐厅', '学生们中午都去学校的餐厅吃饭。', 'Xuéshēngmen zhōngwǔ dōu qù xuéxiào de cāntīng chīfàn.', 'Học sinh đều đi căng tin của trường ăn trưa.'),
    ('长江', '长江是中国最长的河流。', 'Chángjiāng shì Zhōngguó zuì cháng de héliú.', 'Trường Giang là con sông dài nhất ở Trung Quốc.'),
    ('长城', '去年我有机会参观了著名的长城。', 'Qùnián wǒ yǒu jīhuì cānguān le zhùmíng de Chángchéng.', 'Năm ngoái tôi có cơ hội tham quan Vạn Lý Trường Thành nổi tiếng.'),
    ('错误', '老师帮我改正了作文中的错误。', 'Lǎoshī bāng wǒ gǎizhèng le zuòwén zhōng de cuòwù.', 'Giáo viên đã giúp tôi sửa những sai lầm trong bài viết.'),
    ('重新', '因为文件丢失，我不得不重新写报告。', 'Yīnwèi wénjiàn diūshī, wǒ bùdébù chóngxīn xiě bàogào.', 'Vì tài liệu bị mất, tôi đành phải viết lại báo cáo.'),
    ('超过', '他跑步的速度已经超过了所有人。', 'Tā pǎobù de sùdù yǐjīng chāoguò le suǒyǒu rén.', 'Tốc độ chạy của anh ấy đã vượt qua tất cả mọi người.'),
    ('诚实', '诚实是我们必须遵守的原则。', 'Chéngshí shì wǒmen bìxū zūnshǒu de yuánzé.', 'Trung thực là nguyên tắc mà chúng ta phải tuân theo.'),
    ('词语', '学生们在课上学习新的词语。', 'Xuéshēng men zài kè shàng xuéxí xīn de cíyǔ.', 'Học sinh trong lớp học các từ ngữ mới.'),
    ('粗心', '他因为粗心把作业写错了。', 'Tā yīnwèi cūxīn bǎ zuòyè xiě cuò le.', 'Anh ấy vì cẩu thả đã viết sai bài tập.'),
    ('窗户', '请把窗户打开，让空气流通。', 'Qǐng bǎ chuānghù dǎkāi, ràng kōngqì liútōng.', 'Xin hãy mở cửa sổ để không khí lưu thông.'),
    ('猜', '我猜你明天会来。', 'Wǒ cāi nǐ míngtiān huì lái.', 'Tôi đoán bạn sẽ đến vào ngày mai.'),
    ('材料', '老师给我们发了考试的复习材料。', 'Lǎoshī gěi wǒmen fā le kǎoshì de fùxí cáiliào.', 'Giáo viên phát tài liệu ôn thi cho chúng tôi.'),
    ('抽烟', '公共场所禁止抽烟。', 'Gōnggòng chǎngsuǒ jìnzhǐ chōuyān.', 'Nơi công cộng cấm hút thuốc.'),
    ('成功', '他通过努力终于获得了成功。', 'Tā tōngguò nǔlì zhōngyú huòdé le chénggōng.', 'Anh ấy cuối cùng đã thành công nhờ sự cố gắng.'),
    ('成为', '她希望成为一名医生。', 'Tā xīwàng chéngwéi yī míng yīshēng.', 'Cô ấy hy vọng trở thành bác sĩ.'),
    ('差不多', '我们到达的时间差不多是晚上七点。', 'Wǒmen dàodá de shíjiān chàbùduō shì wǎnshàng qī diǎn.', 'Thời gian chúng tôi đến gần như là 7 giờ tối.'),
    ('尝', '你想尝尝这道新菜吗？', 'Nǐ xiǎng cháng cháng zhè dào xīn cài ma?', 'Bạn muốn nếm thử món ăn mới này không?'),
    ('存', '我每个月都会存一部分工资。', 'Wǒ měi gè yuè dūhuì cún yī bùfen gōngzī.', 'Tôi sẽ tiết kiệm một phần lương mỗi tháng.'),
    ('场', '今天晚上有一场重要的足球比赛。', 'Jīntiān wǎnshàng yǒu yì chǎng zhòngyào de zúqiú bǐsài.', 'Tối nay có một trận đấu bóng đá quan trọng.'),
    ('吃惊', '听说他搬到国外了，我很吃惊。', 'Tīngshuō tā bān dào guówài le, wǒ hěn chī jīng.', 'Nghe nói anh ấy đã chuyển ra nước ngoài, tôi rất ngạc nhiên.'),
    ('参观', '我们计划下周参观那个历史博物馆。', 'Wǒmen jìhuà xià zhōu cānguān nàgè lìshǐ bówùguǎn.', 'Chúng tôi dự định vào tuần tới tham quan bảo tàng lịch sử đó.'),
    ('厨房', '她在厨房做了很多美味的菜。', 'Tā zài chúfáng zuò le hěn duō měiwèi de cài.', 'Cô ấy đã nấu rất nhiều món ngon trong phòng bếp.'),
    ('厕所', '请问，厕所在哪里？', 'Qǐngwèn, cèsuǒ zài nǎlǐ?', 'Xin hỏi, nhà vệ sinh ở đâu?'),
    ('出生', '他出生在一个美丽的海边城市。', 'Tā chūshēng zài yí gè měilì de hǎibiān chéngshì.', 'Anh ấy sinh ra tại một thành phố ven biển xinh đẹp.'),
    ('出现', '会议中突然出现了一些技术问题。', 'Huìyì zhōng túrán chūxiàn le yìxiē jìshù wèntí.', 'Trong cuộc họp đột nhiên xuất hiện một số vấn đề kỹ thuật.'),
    ('出差', '下个月我需要去北京出差两周。', 'Xià gè yuè wǒ xūyào qù Běijīng chūchāi liǎng zhōu.', 'Tháng tới tôi cần đi công tác ở Bắc Kinh hai tuần.'),
    ('出发', '我们打算明天一早出发去机场。', 'Wǒmen dǎsuàn míngtiān yì zǎo chūfā qù jīchǎng.', 'Chúng tôi dự định ngày mai sáng sớm xuất phát đến sân bay.'),
    ('传真', '请把合同通过传真发给我。', 'Qǐng bǎ hétóng tōngguò chuánzhēn fā gěi wǒ.', 'Vui lòng gửi hợp đồng cho tôi qua fax.'),
    ('从来', '他从来没有迟到过。', 'Tā cónglái méiyǒu chídào guò.', 'Anh ấy từ trước đến nay chưa bao giờ đến muộn.'),
    ('乘坐', '我们明天打算乘坐火车去北京。', 'Wǒmen míngtiān dǎsuàn chéngzuò huǒchē qù Běijīng.', 'Chúng tôi dự định ngày mai ngồi tàu đi Bắc Kinh.'),
    ('答案', '请把答案写在试卷上。', 'Qǐng bǎ dá''àn xiě zài shìjuàn shàng.', 'Vui lòng viết đáp án lên giấy thi.'),
    ('道歉', '他向老师道歉因为迟到了。', 'Tā xiàng lǎoshī dàoqiàn yīnwèi chídào le.', 'Anh ấy xin lỗi giáo viên vì đến muộn.'),
    ('调查', '公司正在对市场进行调查。', 'Gōngsī zhèngzài duì shìchǎng jìnxíng diàochá.', 'Công ty đang tiến hành điều tra thị trường.'),
    ('肚子', '我肚子疼，需要去医院。', 'Wǒ dùzi téng, xūyào qù yīyuàn.', 'Tôi bị đau bụng, cần đi bệnh viện.'),
    ('等（助词）', '老师说要准备笔、纸等文具。', 'Lǎoshī shuō yào zhǔnbèi bǐ, zhǐ děng wénjù.', 'Giáo viên nói cần chuẩn bị bút, giấy và các văn phòng phẩm khác.'),
    ('短信', '我刚收到你的短信，谢谢！', 'Wǒ gāng shōudào nǐ de duǎnxìn, xièxiè!', 'Tôi vừa nhận được tin nhắn của bạn, cảm ơn!'),
    ('登机牌', '请出示你的登机牌和护照。', 'Qǐng chūshì nǐ de dēngjīpái hé hùzhào.', 'Vui lòng xuất trình thẻ lên tàu và hộ chiếu của bạn.'),
    ('掉', '我的手机今天不小心掉了。', 'Wǒ de shǒujī jīntiān bù xiǎoxīn diào le.', 'Điện thoại của tôi hôm nay vô tình bị rơi.'),
    ('打针', '医生给小孩打针以防感冒。', 'Yīshēng gěi xiǎohái dǎ zhēn yǐ fáng gǎnmào.', 'Bác sĩ tiêm cho trẻ để phòng cảm.'),
    ('打招呼', '见到老师要主动打招呼。', 'Jiàn dào lǎoshī yào zhǔdòng dǎ zhāo hū.', 'Gặp thầy cô nên chủ động chào hỏi.'),
    ('打折', '这个商店周末会打折促销。', 'Zhège shāngdiàn zhōumò huì dǎ zhé cùxiāo.', 'Cửa hàng này cuối tuần sẽ giảm giá khuyến mãi.'),
    ('打扰', '很抱歉打扰您工作了。', 'Hěn bàoqiàn dǎrǎo nín gōngzuò le.', 'Rất xin lỗi đã làm phiền công việc của bạn.'),
    ('打扮', '她今天打扮得非常漂亮。', 'Tā jīntiān dǎbàn de fēicháng piàoliang.', 'Cô ấy hôm nay trang điểm rất đẹp.'),
    ('打印', '请帮我打印这份文件。', 'Qǐng bāng wǒ dǎyìn zhè fèn wénjiàn.', 'Làm ơn giúp tôi in tài liệu này.'),
    ('戴', '外出时记得戴口罩。', 'Wàichū shí jìde dài kǒuzhào.', 'Khi ra ngoài nhớ đeo khẩu trang.'),
    ('得意', '他考试得了高分，非常得意。', 'Tā kǎoshì dé le gāofēn, fēicháng déyì.', 'Anh ấy kiểm tra được điểm cao, rất đắc ý.'),
    ('得（助动词）', '你说得很清楚，我明白了。', 'Nǐ shuō de hěn qīngchu, wǒ míngbái le.', 'Bạn nói rất rõ, tôi hiểu rồi.'),
    ('当时', '那个项目当时非常受欢迎。', 'Nàgè xiàngmù dāngshí fēicháng shòu huānyíng.', 'Dự án đó lúc đó rất được ưa chuộng.'),
    ('当', '我想当老师教学生中文。', 'Wǒ xiǎng dāng lǎoshī jiào xuéshēng zhōngwén.', 'Tôi muốn làm giáo viên dạy học sinh tiếng Trung.'),
    ('底', '请把书放在桌子的底下。', 'Qǐng bǎ shū fàng zài zhuōzi de dǐ xià.', 'Xin hãy để sách dưới đáy bàn.'),
    ('导游', '导游带我们参观了名胜古迹。', 'Dǎoyóu dài wǒmen cānguānle míngshèng gǔjì.', 'Hướng dẫn viên du lịch dẫn chúng tôi tham quan các thắng cảnh nổi tiếng.'),
    ('对面', '学校对面有一家很好的餐厅。', 'Xuéxiào duìmiàn yǒu yī jiā hěn hǎo de cāntīng.', 'Đối diện trường có một nhà hàng rất ngon.'),
