    ('作者', '这本书的作者写了很多畅销书。', 'Zhè běn shū de zuòzhě xiě le hěn duō chàngxiāoshū.', 'Tác giả của cuốn sách này đã viết nhiều sách bán chạy.'),
    ('作用', '运动对身体有很好的作用。', 'Yùndòng duì shēntǐ yǒu hěn hǎo de zuòyòng.', 'Thể thao có tác dụng rất tốt đối với sức khỏe.'),
    ('作家', '他是一个著名的作家，写了很多小说。', 'Tā shì yīgè zhùmíng de zuòjiā, xiě le hěn duō xiǎoshuō.', 'Anh ấy là một tác gia nổi tiếng, đã viết nhiều tiểu thuyết.'),
    ('仔细', '请你仔细看清楚合同的每一条内容。', 'Qǐng nǐ zǐxì kàn qīngchǔ hétóng de měi yītiáo nèiróng.', 'Xin bạn hãy xem kỹ từng điều khoản trong hợp đồng.'),
    ('之', '这是我之所以选择这个学校的原因。', 'Zhè shì wǒ zhī suǒyǐ xuǎnzé zhège xuéxiào de yuányīn.', 'Đây là lý do tôi chọn trường này.'),
    ('主意', '你的主意很好，我们可以试试看。', 'Nǐ de zhǔyì hěn hǎo, wǒmen kěyǐ shì shì kàn.', 'Ý tưởng của bạn rất tốt, chúng ta có thể thử xem.'),
    ('专门', '他专门学习汉语已经三年了。', 'Tā zhuānmén xuéxí hànyǔ yǐjīng sān nián le.', 'Anh ấy đã học tiếng Hán chuyên môn được ba năm rồi.'),
    ('专业', '我大学的专业是计算机科学。', 'Wǒ dàxué de zhuānyè shì jìsuànjī kēxué.', 'Chuyên ngành đại học của tôi là khoa học máy tính.')
),
updated_template_cards as (
  update public.template_cards as card
  set
    example_cn = example.example_cn,
    example_pinyin = example.example_pinyin,
    example_vi = example.example_vi,
    sentence_audio_url = null
  from public.template_decks as deck,
    hsk4_context_examples as example
  where card.template_deck_id = deck.id
    and deck.slug = 'hsk4-co-ban'
    and card.chinese = example.chinese
  returning card.id
)
update public.cards as card
set
  example_cn = example.example_cn,
  example_pinyin = example.example_pinyin,
  example_vi = example.example_vi,
  sentence_audio_url = null
from public.decks as deck,
  hsk4_context_examples as example
where card.deck_id = deck.id
  and card.user_id = deck.user_id
  and (
    deck.source_template_slug = 'hsk4-co-ban'
    or (deck.source_template_slug is null and deck.name = 'HSK4 cơ bản')
  )
  and card.chinese = example.chinese
  and (
    nullif(btrim(card.example_cn), '') is null
    or card.example_cn like '这件事和%有关。'
    or card.example_cn like '今天我们练习%这个词。'
    or card.example_pinyin like 'Zhe jian shi he % youguan.'
    or card.example_pinyin like 'Jintian women lianxi % zhe ge ci.'
  );
